hospitalityGroupsHTML(){
  // Build groups from restaurant data for current city
  const restaurants = this.getRestaurants();
  const groupMap = {};
  restaurants.filter(r => r.group).forEach(r => {
    if(!groupMap[r.group]) groupMap[r.group] = [];
    groupMap[r.group].push(r);
  });
  // Only show groups with 2+ restaurants
  const multiGroups = Object.entries(groupMap).filter(([k,v]) => v.length >= 2).sort((a,b) => {
    // If HOSPITALITY_GROUPS data exists, sort by overall score; otherwise by avg restaurant score
    const scoreA = HOSPITALITY_GROUPS[a[0]] ? HOSPITALITY_GROUPS[a[0]].score : Math.round(a[1].reduce((s,r) => s+r.score, 0) / a[1].length);
    const scoreB = HOSPITALITY_GROUPS[b[0]] ? HOSPITALITY_GROUPS[b[0]].score : Math.round(b[1].reduce((s,r) => s+r.score, 0) / b[1].length);
    return scoreB - scoreA;
  });
  if(multiGroups.length === 0) return '<div class="empty-state"><div class="empty-icon">🏢</div><div class="empty-title">Hospitality Groups</div><div class="empty-desc">Group data coming soon for '+S.city+'</div></div>';

  return `
