      <div style="font-size:12px;color:var(--text3)">Multi-concept groups operating in ${S.city||'Dallas'}</div>
    </div>
    ${multiGroups.map(([name, rests]) => {
      const gd = HOSPITALITY_GROUPS[name];
      const avg = gd ? gd.score : Math.round(rests.reduce((s,r) => s+r.score, 0) / rests.length);
      const color = avg >= 90 ? 'var(--gold)' : avg >= 80 ? '#4c9a6a' : 'var(--text3)';
      const metaLine = gd ? `Est. ${gd.founded} · ${gd.concepts} concepts · ${gd.flagship}` : `${rests.length} concepts in ${S.city}`;
      const desc = gd ? gd.description : '';
      const website = gd && gd.website ? gd.website : '';
      const michelinCount = gd ? (gd.michelinCount||0) : 0;
      return `
      <div style="background:var(--card);border:1px solid var(--border);border-radius:16px;overflow:hidden;margin-bottom:14px">
        <!-- Header -->
        <div style="background:linear-gradient(135deg,rgba(201,168,76,.08),rgba(201,168,76,.02));padding:14px 14px 11px;border-bottom:1px solid var(--border)">
          <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:10px">
            <div style="flex:1">
              <div style="font-size:15px;font-weight:700;color:var(--text);line-height:1.2">${name}</div>
              <div style="font-size:11px;color:var(--text3);margin-top:3px">${metaLine}</div>
              ${michelinCount>0?`<div style="font-size:10px;color:var(--gold);margin-top:2px">⭐ ${michelinCount} Michelin Recommended</div>`:''}
              ${website?`<a href="${website}" target="_blank" style="font-size:10px;color:var(--gold);text-decoration:none;margin-top:3px;display:inline-block">🌐 Website →</a>`:''}
            </div>
            <div style="text-align:center;flex-shrink:0">
              <div style="font-size:28px;font-weight:700;color:${color};line-height:1">${avg}</div>
              <div style="font-size:9px;color:var(--text3)">Overall</div>
            </div>
          </div>
        </div>
        <!-- Body -->
        <div style="padding:12px 14px">
          ${desc?`<div style="font-size:12px;color:var(--text2);line-height:1.6;margin-bottom:12px">${desc}</div>`:''}
          <!-- Restaurant list -->
          <div>
            ${rests.sort((a,b) => b.score - a.score).map(r => `
              <div onclick="A.openDetailFromGroup(${r.id},'groups')" style="display:flex;align-items:center;justify-content:space-between;padding:8px 0;border-bottom:1px solid var(--border);cursor:pointer">
                <div>
                  <div style="font-size:13px;font-weight:600;color:var(--text)">${r.name}</div>
                  <div style="font-size:11px;color:var(--text2)">${r.cuisine} · ${r.neighborhood}</div>
                </div>
                <div style="font-size:16px;font-weight:700;color:var(--gold)">${r.score}</div>
              </div>
            `).join('')}
          </div>
        </div>
      </div>`;
    }).join('')}
  `;

